+// ─── Pixel Art Characters (16x24) ───────────────────────────────────
+
+// Each character is drawn with proper pixel art proportions:
+// Head: 8x8 pixels
+// Torso: 8x8 pixels
+// Legs: 8x8 pixels
+// Arms: 4x8 pixels each (overlapping torso)
+// Outlines, shading, and distinctive features per character type.
+
+function drawPixelCharacter(
+  ctx: CanvasRenderingContext2D,
+  type: CharacterType,
+  x: number,
+  y: number,
+  scale: number,
+  flipH = false,
+) {
+  const p = PALETTE_MAP[type];
+  if (!p) return;
+
+  // Helper to draw a pixel at (px, py) relative to (x,y)
+  function pxDraw(px: number, py: number, color: string) {
+    const drawX = flipH ? x + (15 - px) * scale : x + px * scale;
+    ctx.fillStyle = color;
+    ctx.fillRect(Math.round(drawX), Math.round(y + py * scale), scale, scale);
+  }
+
+  // Outline color (dark)
+  const outline = p.O || '#1a1018';
+
+  // Draw head with outline and shading
+  function drawHead() {
+    // Head outline 8x8
+    const headOutline = [
+      '  OOOOOO  ',
+      ' OOOOOOOO ',
+      'OOOOOOOOOO',
+      'OOOOOOOOOO',
+      'OOOOOOOOOO',
+      'OOOOOOOOOO',
+      ' OOOOOOOO ',
+      '  OOOOOO  ',
+    ];
+    // Head fill pattern with skin and shading
+    const headFill = [
+      '  sssss  ',
+      ' sssssss ',
+      'ssssssss ',
+      'ssssssss ',
+      'ssssssss ',
+      'ssssssss ',
+      ' ssssss ',
+      '  ssss  ',
+    ];
+    // Draw outline
+    for (let py = 0; py < 8; py++) {
+      for (let px = 0; px < 10; px++) {
+        if (headOutline[py][px] === 'O') pxDraw(px + 4, py, outline);
+      }
+    }
+    // Draw skin with shading
+    for (let py = 0; py < 8; py++) {
+      for (let px = 0; px < 8; px++) {
+        const ch = headFill[py][px];
+        if (ch === 's') {
+          // Use skin color and shade for cheeks and forehead
+          let col = p.S;
+          if ((py === 1 && (px === 1 || px === 6)) || (py === 2 && (px === 0 || px === 7))) {
+            col = p.s; // shaded skin
+          }
+          pxDraw(px + 5, py + 1, col);
+        }
+      }
+    }
+  }
+
+  // Draw torso with outline, primary and secondary colors and shading
+  function drawTorso() {
+    // Torso outline 8x8
+    const torsoOutline = [
+      ' OOOOOOO ',
+      'OOOOOOOOO',
+      'O       O',
+      'O       O',
+      'O       O',
+      'O       O',
+      'OOOOOOOOO',
+      ' OOOOOOO ',
+    ];
+    // Torso fill pattern with primary and secondary colors
+    const torsoFill = [
+      ' ppppppp ',
+      ' ppppppp ',
+      ' p     p ',
+      ' p     p ',
+      ' p     p ',
+      ' p     p ',
+      ' ppppppp ',
+      '  ppppp  ',
+    ];
+    // Draw outline
+    for (let py = 0; py < 8; py++) {
+      for (let px = 0; px < 9; px++) {
+        if (torsoOutline[py][px] === 'O') pxDraw(px + 4, py + 9, outline);
+      }
+    }
+    // Draw fill with primary and secondary colors and shading
+    for (let py = 0; py < 8; py++) {
+      for (let px = 0; px < 9; px++) {
+        const ch = torsoFill[py][px];
+        if (ch === 'p') {
+          // Use primary color with shading gradient top to bottom
+          let col = p.P;
+          if (py > 4) col = p.p; // shaded primary
+          pxDraw(px + 4, py + 9, col);
+        }
+      }
+    }
+  }
+
+  // Draw legs with outline and shading
+  function drawLegs() {
+    // Legs outline 8x8
+    const legsOutline = [
+      ' O   O O ',
+      ' O   O O ',
+      ' O   O O ',
+      ' O   O O ',
+      ' O   O O ',
+      ' O   O O ',
+      ' O   O O ',
+      '  OOOOO  ',
+    ];
+    // Legs fill pattern with secondary color and shading
+    const legsFill = [
+      ' c   c c ',
+      ' c   c c ',
+      ' c   c c ',
+      ' c   c c ',
+      ' c   c c ',
+      ' c   c c ',
+      ' c   c c ',
+      '  ccccc  ',
+    ];
+    // Draw outline
+    for (let py = 0; py < 8; py++) {
+      for (let px = 0; px < 9; px++) {
+        if (legsOutline[py][px] === 'O') pxDraw(px + 4, py + 17, outline);
+      }
+    }
+    // Draw fill with secondary color and shading
+    for (let py = 0; py < 8; py++) {
+      for (let px = 0; px < 9; px++) {
+        const ch = legsFill[py][px];
+        if (ch === 'c') {
+          // Use secondary color with shading gradient bottom to top
+          let col = p.C;
+          if (py < 4) col = p.c; // shaded secondary
+          pxDraw(px + 4, py + 17, col);
+        }
+      }
+    }
+  }
+
+  // Draw arms with outline and shading
+  function drawArms() {
+    // Left arm 4x8
+    const leftArmOutline = [
+      ' OOOO ',
+      'O    O',
+      'O    O',
+      'O    O',
+      'O    O',
+      'O    O',
+      'O    O',
+      ' OOOO ',
+    ];
+    const leftArmFill = [
+      ' aaaa ',
+      ' aaaa ',
+      ' aaaa ',
+      ' aaaa ',
+      ' aaaa ',
+      ' aaaa ',
+      ' aaaa ',
+      ' aaaa ',
+    ];
+    // Right arm 4x8
+    const rightArmOutline = leftArmOutline;
+    const rightArmFill = leftArmFill;
+
+    // Draw left arm at (0,9)
+    for (let py = 0; py < 8; py++) {
+      for (let px = 0; px < 6; px++) {
+        if (leftArmOutline[py][px] === 'O') pxDraw(px, py + 9, outline);
+      }
+    }
+    for (let py = 0; py < 8; py++) {
+      for (let px = 0; px < 6; px++) {
+        if (leftArmFill[py][px] === 'a') {
+          let col = p.A;
+          if (py > 4) col = p.a;
+          pxDraw(px, py + 9, col);
+        }
+      }
+    }
+
+    // Draw right arm at (12,9)
+    for (let py = 0; py < 8; py++) {
+      for (let px = 0; px < 6; px++) {
+        if (rightArmOutline[py][px] === 'O') pxDraw(px + 12, py + 9, outline);
+      }
+    }
+    for (let py = 0; py < 8; py++) {
+      for (let px = 0; px < 6; px++) {
+        if (rightArmFill[py][px] === 'a') {
+          let col = p.A;
+          if (py > 4) col = p.a;
+          pxDraw(px + 12, py + 9, col);
+        }
+      }
+    }
+  }
+
+  // Draw distinctive features per character type
+  function drawFeatures() {
+    switch (type) {
+      case 'king':
+        // Crown on head top center
+        for (let px = 7; px <= 8; px++) {
+          pxDraw(px, 0, p.G);
+          pxDraw(px, 1, p.g);
+        }
+        pxDraw(6, 1, p.G);
+        pxDraw(9, 1, p.G);
+        break;
+      case 'nobility':
+        // Fancy collar around neck (torso top)
+        for (let px = 5; px <= 11; px++) {
+          pxDraw(px, 9, p.K);
+          pxDraw(px, 10, p.k);
+        }
+        break;
+      case 'knight':
+        // Helmet visor on head center
+        for (let px = 6; px <= 9; px++) {
+          pxDraw(px, 3, p.M);
+          pxDraw(px, 4, p.m);
+        }
+        break;
+      case 'squire':
+        // Simple tabard stripe torso center
+        for (let py = 12; py <= 14; py++) {
+          pxDraw(8, py, p.F);
+        }
+        break;
+      case 'healer':
+        // Cross on torso front
+        pxDraw(7, 12, p.F);
+        pxDraw(8, 12, p.F);
+        pxDraw(7, 13, p.F);
+        pxDraw(8, 13, p.F);
+        pxDraw(7, 14, p.F);
+        pxDraw(8, 14, p.F);
+        break;
+      case 'sentinel':
+        // Red shoulder pads
+        for (let py = 9; py <= 11; py++) {
+          pxDraw(3, py, p.R);
+          pxDraw(12, py, p.R);
+        }
+        break;
+      case 'scribe':
+        // Quill behind head (left side)
+        pxDraw(3, 2, p.B);
+        pxDraw(2, 3, p.B);
+        pxDraw(3, 3, p.b);
+        break;
+      case 'judge':
+        // Wig curls on head sides
+        pxDraw(4, 1, p.W);
+        pxDraw(11, 1, p.W);
+        pxDraw(3, 2, p.w);
+        pxDraw(12, 2, p.w);
+        break;
+      case 'blacksmith':
+        // Apron front torso
+        for (let py = 11; py <= 15; py++) {
+          pxDraw(7, py, p.M);
+          pxDraw(8, py, p.M);
+        }
+        break;
+    }
+  }
+
+  // Draw all parts
+  drawHead();
+  drawTorso();
+  drawLegs();
+  drawArms();
+  drawFeatures();
+}
+
+// Replace old drawCharacter with new pixel art version
+function drawCharacter(
+  ctx: CanvasRenderingContext2D,
+  type: CharacterType,
+  x: number,
+  y: number,
+  scale: number,
+  flipH = false,
+) {
+  drawPixelCharacter(ctx, type, x, y, scale, flipH);
+}
+
